var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"도착하셨군요, 사령관님.","JPN":"到着されたのですね、司令官。","ENG":"You came, Commander.","TWN":"您到了啊，司令官大人。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 하지만 한가하게 인사나 나눌 기분이 아니군.","JPN":"ああ、だが、のんびり挨拶する気分ではないな。","ENG":"Yes, but I'm not in the mood for pleasantries.","TWN":"是啊，不過我可沒心情和你閒聊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지원 병력도 없이 차원 폭풍 안으로 진입하다니 대체 무슨 생각인가?","JPN":"援軍もいないのに次元の暴風の中に入るなんて、どういうつもりなんだ？","ENG":"What were you thinking, entering the dimensional storm without backup?","TWN":"在沒有援軍的情況下，你竟然就直接進到了次元風暴內部？你到底在想什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>등대</color>에 대해서는 들으셨을 텐데요?","JPN":"<color=#ffd34c>灯台</color>についてはお聞きになったと思いますが？","ENG":"You've heard about the <color=#ffd34c>Lighthouse</color>, haven't you?","TWN":"我想，您應該已經聽到關於<color=#ffd34c>燈塔</color>的說明了吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"나름대로 준비를 하고 들어왔으니 너무 걱정하지 않으셔도 됩니다.","JPN":"万全を期して入ったので、ご心配には及びません。","ENG":"I came in prepared. You don't have to worry about me.","TWN":"我已經做了相應的準備，您可以不用這麼擔心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"꽤나 과감해졌군...... 예전에는 그런 성격이 아니었는데.","JPN":"ずいぶん果敢になったな……以前はそんな性格ではなかったのに。","ENG":"You've become bold. You were never like this before.","TWN":"變得還真果敢哪……你以前可不是這種性格。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 우리는 여기서 뭘 하면 되지?","JPN":"では、我々はここで何をすれば良いのだ？","ENG":"What do you want us to do here?","TWN":"那我們在這裡需要做什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제가 목표를 수거할 때까지 등대를 지켜 주시면 됩니다.","JPN":"私が目標を回収するまで、灯台を守っていただければ。","ENG":"I'd like you to protect the Lighthouse until I collect my target.","TWN":"在我回收完目標前，保護好燈塔就可以了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍의 영향으로 침식체들이 그쪽으로 몰려들 수도 있으니까요.","JPN":"次元の暴風の影響で、侵食体どもがそちらに押し寄せるかもしれません。","ENG":"I don't want it to be attacked by the C.O.s that have gathered because of this dimensional storm.","TWN":"受到次元風暴的影響，侵蝕體可能會殺到妳那邊去。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어이, 부사령관 아저씨.","JPN":"ちょっと、副司令官のおじさん。","ENG":"Hey, Deputy Commander.","TWN":"喂，副司令官大叔。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이런 데까지 불러서 사람을 경비견으로 쓸 거면 좀 더 자세한 설명이 필요하다고 생각하지 않아?","JPN":"こんなところまで呼びつけて私たちを警備犬代わりにしたいなら、\\nもう少し詳しい説明が必要なんじゃないの？","ENG":"You made us come all the way here to be your watchdogs. Don't you think we deserve a more detailed explanation?","TWN":"把人叫到這種地方當看門狗，你不覺得自己需要多解釋幾句嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우린 당신 말 한마디에 군말 없이 따라야만 하는 하인이 아니라고.","JPN":"私たちはあなたの言葉に絶対服従しなければならない下僕ではないわよ。","ENG":"We're not your servants who are at your beck and call, you know.","TWN":"我們又不是你的僕人，你說一句話我們就得毫無怨言地照辦。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하인은 아니지만 군인이지.","JPN":"下僕ではないが、軍人だろう？","ENG":"No, you're not. But you're soldiers.","TWN":"雖然不是僕人，但你們是軍人吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설명이 부족하더라도 명령에 따르는 게 군인으로서의 자세 아닌가?","JPN":"説明が足りなくても命令に従うのが軍人魂じゃないのか？","ENG":"And soldiers must follow their orders, explanations or not.","TWN":"就算說明不夠充分，但遵從命令，不就是作為軍人該有的態度嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"난 군인이 아니라 민간 군사 협력 요원이라고!","JPN":"アタシは軍人ではなく、民間の軍事協力要員なの！","ENG":"I'm not a soldier—I'm a civilian collaborator!","TWN":"我又不是軍人，我是民間軍事合作要員！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"명령에 따라 작전을 수행하기로 <color=#ffd34c>계약한</color> 민간 <color=#ffd34c>군사</color> 요원이지.","JPN":"正確に言うと、命令に従って作戦遂行することを<color=#ffd34c>契約した</color>民間の<color=#ffd34c>軍事</color>要員だ。","ENG":"You're a civilian <color=#ffd34c>collaborator</color> who has <color=#ffd34c>agreed</color> to follow orders.","TWN":"是簽定了<color=#ffd34c>契約</color>，要遵從命令進行作戰的民間<color=#ffd34c>軍事</color>要員吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"우리가 자네를 고용하느라 대체 몇 건이나 되는 군사보안법 위반에 대한 기소를 유예했는지 모르지 않을 텐데?","JPN":"我々が君たちを雇うために、軍事保安法違反まわりの案件をいくつ起訴猶予にしたか、知ってるだろう？","ENG":"You didn't forget that we protected you from being prosecuted for multiple counts of national security law violations in exchange for your service, did you?","TWN":"妳又不是不知道我們為了雇傭妳，到底推遲了多少違反軍事安全法的起訴吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이런 불성실한 태도가 알려지면 자네를 관타나모에 처넣고 싶어하는 군검사들이 아주 좋아할 거야.","JPN":"こんな不真面目な態度が知られたら、\\n君をグアンタナモにぶちこみたがっている軍警察が大喜びするだろうな。","ENG":"If you no longer wish to work for us, then I can contact the prosecutor for you. He'd love to send you to Guantanamo.","TWN":"如果知道妳這麼不忠誠的態度，那些想把妳扔進關塔那摩的軍事檢察官應該會很高興吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아니 그건......","JPN":"い、いや、それは……","ENG":"W-well, that's...","TWN":"不，那個……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};